347→pub fn load_repo(
348→    path: &Path,
349→) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
350→    let config = StackedConfig::with_defaults();
351→    let settings = UserSettings::from_config(config)?;
352→    let store_factories = StoreFactories::default();
353→    let working_copy_factories = default_working_copy_factories();
354→
355→    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
356→    let repo = workspace.repo_loader().load_at_head().block_on()?;
357→
358→    Ok((workspace, repo))
359→}
