 53→            &args.repo,
 54→            args.pos_rev.as_deref(),
 55→            both_count,
 56→            common::format_chid,
 57→        )?;
 58→        for (i, line) in lines.iter().enumerate() {
 59→            if i == anchor {
 60→                println!("{}", common::bold(line));
 61→            } else {
 62→                println!("{line}");
 63→            }
 64→        }
 65→        return Ok(());
 66→    }
