 68→    // Resolve the primary commit ID for highlighting
 69→    let primary_ids = common::resolve_revset(&workspace, &repo, &resolved.primary_rev)?;
 70→    let primary_id = primary_ids.first();
 71→
 72→    let mut results: Vec<(String, bool)> = Vec::new();
 73→    let mut count = 0;
