  1→use std::path::PathBuf;
  2→use std::sync::Arc;
  3→
  4→use chrono::Offset;
  5→use clap::Args;
  6→use jj_lib::backend::TreeValue;
  7→use jj_lib::commit::Commit;
  8→use jj_lib::hex_util::encode_reverse_hex;
  9→use jj_lib::matchers::EverythingMatcher;
 10→use jj_lib::merged_tree::TreeDiffIterator;
 11→use jj_lib::object_id::ObjectId;
 12→use jj_lib::repo::{ReadonlyRepo, Repo};
 13→use pollster::FutureExt;
 14→
 15→use crate::common;
 16→
 17→#[derive(Args, Debug)]
 18→pub struct ShowArgs {
 19→    /// Revision to show (default: @)
 20→    #[arg(short, long, default_value = "@")]
 21→    pub revision: String,
 22→
 23→    /// Path to jj repo (default: current directory)
 24→    #[arg(short = 'R', long, default_value = ".")]
 25→    pub repo: PathBuf,
 26→}
 27→
 28→pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
 29→    let (workspace, repo) = common::load_repo(&args.repo)?;
 30→    let commit_ids = common::resolve_revset(&workspace, &repo, &args.revision)?;
 31→
 32→    if commit_ids.is_empty() {
 33→        return Err(format!("no commit found for revision '{}'", args.revision).into());
 34→    }
 35→
 36→    let root_commit_id = repo.store().root_commit_id().clone();
 37→    let commit_id = &commit_ids[0];
 38→    if *commit_id == root_commit_id {
 39→        return Err("cannot show root commit".into());
 40→    }
 41→
 42→    let commit = repo.store().get_commit(commit_id)?;
 43→
 44→    print_header(&commit, &repo);
 45→    print_description(&commit);
 46→    print_diff(&commit, &repo)?;
 47→
 48→    Ok(())
 49→}
 50→
 51→fn print_header(commit: &Commit, repo: &Arc<ReadonlyRepo>) {
 52→    let commit_hex = commit.id().hex();
 53→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
 54→
 55→    println!("Commit ID: {commit_hex}");
 56→    println!("Change ID: {change_hex}");
 57→
 58→    // Bookmarks
 59→    let bookmark_str = format_bookmarks(commit, repo);
 60→    if !bookmark_str.is_empty() {
 61→        println!("Bookmarks: {bookmark_str}");
 62→    }
 63→
 64→    // Author
 65→    let author = commit.author();
 66→    println!(
 67→        "Author   : {} <{}> ({})",
 68→        author.name,
 69→        author.email,
 70→        format_timestamp(&author.timestamp)
 71→    );
 72→
 73→    // Committer
 74→    let committer = commit.committer();
 75→    println!(
 76→        "Committer: {} <{}> ({})",
 77→        committer.name,
 78→        committer.email,
 79→        format_timestamp(&committer.timestamp)
 80→    );
 81→}
 82→
 83→fn format_bookmarks(commit: &Commit, repo: &Arc<ReadonlyRepo>) -> String {
 84→    let view = repo.view();
 85→    let mut names: Vec<String> = Vec::new();
 86→
 87→    for (name, local_remote) in view.bookmarks() {
 88→        // Local bookmark
 89→        if local_remote
 90→            .local_target
 91→            .added_ids()
 92→            .any(|id| id == commit.id())
 93→        {
 94→            names.push(name.as_str().to_string());
 95→        }
 96→        // Remote bookmarks
 97→        for (remote_name, remote_ref) in &local_remote.remote_refs {
 98→            if remote_ref.target.added_ids().any(|id| id == commit.id()) {
 99→                names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
100→            }
101→        }
102→    }
103→
104→    names.join(" ")
105→}
106→
107→fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
108→    let millis = ts.timestamp.0;
109→    let secs = millis / 1000;
110→    let tz_minutes = ts.tz_offset;
111→
112→    let dt = chrono::DateTime::from_timestamp(secs, 0)
113→        .unwrap_or_default()
114→        .with_timezone(
115→            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()),
116→        );
117→
118→    dt.format("%Y-%m-%d %H:%M:%S").to_string()
119→}
120→
121→fn print_description(commit: &Commit) {
122→    let desc = commit.description();
123→    println!();
124→    if desc.is_empty() {
125→        println!("    (no description set)");
126→    } else {
127→        for line in desc.lines() {
128→            println!("    {line}");
129→        }
130→    }
131→    println!();
132→}
133→
134→fn print_diff(
135→    commit: &Commit,
136→    repo: &Arc<ReadonlyRepo>,
137→) -> Result<(), Box<dyn std::error::Error>> {
138→    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
139→    let commit_tree = commit.tree();
140→
141→    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
142→
143→    for entry in diff_iter {
144→        let diff = entry.values?;
145→        let before = diff.before.as_resolved().cloned().flatten();
146→        let after = diff.after.as_resolved().cloned().flatten();
147→
148→        // Skip tree (directory) entries — only show files
149→        if matches!(&before, Some(TreeValue::Tree(_)))
150→            || matches!(&after, Some(TreeValue::Tree(_)))
151→        {
152→            continue;
153→        }
154→
155→        let path_str = entry.path.as_internal_file_string();
156→
157→        match (before, after) {
158→            (None, Some(value)) => {
159→                println!("Added {} {path_str}:", file_type_str(&value));
160→            }
161→            (Some(_), None) => {
162→                println!(
163→                    "Removed {} {path_str}:",
164→                    file_type_str_from_merged(&diff.before),
165→                );
166→            }
167→            (Some(_), Some(value)) => {
168→                println!("Modified {} {path_str}:", file_type_str(&value));
169→            }
170→            (None, None) => {
171→                // Conflicted or both absent — skip
172→            }
173→        }
174→    }
175→
176→    Ok(())
177→}
178→
179→fn file_type_str(value: &TreeValue) -> &'static str {
180→    match value {
181→        TreeValue::File {
182→            executable: false, ..
183→        } => "regular file",
184→        TreeValue::File {
185→            executable: true, ..
186→        } => "executable file",
187→        TreeValue::Symlink(_) => "symlink",
188→        TreeValue::Tree(_) => "tree",
189→        TreeValue::GitSubmodule(_) => "git submodule",
190→    }
191→}
192→
193→fn file_type_str_from_merged(merged: &jj_lib::merge::Merge<Option<TreeValue>>) -> &'static str {
194→    if let Some(Some(value)) = merged.as_resolved() {
195→        file_type_str(value)
196→    } else {
197→        "file"
198→    }
199→}
200→

