        let parent = repo.store().get_commit(parent_id)?;
        println!("Parent:    {}", common::format_commit_short(&parent));
    }

    // Children
    let children_ids = common::resolve_revset(
        workspace,
        repo,
        &format!("children({})", commit.id().hex()),
    )?;
    for child_id in &children_ids {
        if *child_id == root_commit_id {
            continue;
        }
        let child = repo.store().get_commit(child_id)?;
        println!("Child:     {}", common::format_commit_short(&child));
    }

    // Bookmarks
    let bookmark_str = format_bookmarks(commit, repo);
    if !bookmark_str.is_empty() {
        println!("Bookmarks: {bookmark_str}");
    }

    // Follows (nearest ancestor tag)
    let follows = find_nearest_tag(commit, repo, true)?;
    println!("Follows:   {}", follows.as_deref().unwrap_or(""));

