                let cg = ce.generation_number();
                if tg > cg { tg - cg } else { cg - tg }
            } else {
                continue;
            };

            if best.is_none() || distance < best.as_ref().unwrap().1 {
                best = Some((name.as_str().to_string(), distance));
            }
        }
    }

    Ok(best.map(|(name, _)| name))
