fn print_header(
    commit: &Commit,
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
) -> Result<(), Box<dyn std::error::Error>> {
    // Author
    let author = commit.author();
    println!(
        "Author:    {} <{}> ({})",
        author.name,
        author.email,
        format_timestamp(&author.timestamp)
    );

    // Committer
    let committer = commit.committer();
    println!(
        "Committer: {} <{}> ({})",
        committer.name,
        committer.email,
        format_timestamp(&committer.timestamp)
    );

    // Parents
    let root_commit_id = repo.store().root_commit_id().clone();
    for parent_id in commit.parent_ids() {
        if *parent_id == root_commit_id {
            continue;
        }
        let parent = repo.store().get_commit(parent_id)?;
        println!("Parent:    {}", common::format_commit_short(&parent));
    }

    // Children
    let children_ids = common::resolve_revset(
        workspace,
        repo,
        &format!("children({})", commit.id().hex()),
    )?;
    for child_id in &children_ids {
        if *child_id == root_commit_id {
            continue;
        }
        let child = repo.store().get_commit(child_id)?;
        println!("Child:     {}", common::format_commit_short(&child));
    }

    // Bookmarks
    let bookmark_str = format_bookmarks(commit, repo);
    if !bookmark_str.is_empty() {
        println!("Bookmarks: {bookmark_str}");
    }

    // Follows (nearest ancestor tag)
    let follows = find_nearest_tag(commit, repo, true)?;
    println!("Follows:   {}", follows.as_deref().unwrap_or(""));

    // Precedes (nearest descendant tag)
    let precedes = find_nearest_tag(commit, repo, false)?;
    println!("Precedes:  {}", precedes.as_deref().unwrap_or(""));

    Ok(())
}

fn find_nearest_tag(
    commit: &Commit,
    repo: &Arc<ReadonlyRepo>,
    ancestor: bool,
) -> Result<Option<String>, Box<dyn std::error::Error>> {
    let view = repo.view();
    let index = repo.index();
    let commit_id = commit.id();

    let mut best: Option<(String, u64)> = None;

    for (name, local_remote) in view.tags() {
        for tag_commit_id in local_remote.local_target.added_ids() {
            let is_related = if ancestor {
                // Tag is ancestor of commit (tag comes before)
                index.is_ancestor(tag_commit_id, commit_id)?
            } else {
                // Tag is descendant of commit (tag comes after)
                index.is_ancestor(commit_id, tag_commit_id)?
            };

            if !is_related || tag_commit_id == commit_id {
                continue;
            }

            // Use generation number as distance proxy
            let tag_entry = index.entry_by_id(tag_commit_id);
            let commit_entry = index.entry_by_id(commit_id);
            let distance = if let (Ok(te), Ok(ce)) = (tag_entry, commit_entry) {
                let tg = te.generation_number();
                let cg = ce.generation_number();
                if tg > cg { tg - cg } else { cg - tg }
            } else {
                continue;
            };

            if best.is_none() || distance < best.as_ref().unwrap().1 {
                best = Some((name.as_str().to_string(), distance));
            }
        }
    }

    Ok(best.map(|(name, _)| name))
}

