pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
    let (workspace, repo) = common::load_repo(&args.repo)?;
    let commit_ids = common::resolve_revset(&workspace, &repo, &args.revision)?;

