fn print_header(
    commit: &Commit,
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
) -> Result<(), Box<dyn std::error::Error>> {
    // Author
    let author = commit.author();
    println!(
        "Author:    {} <{}> ({})",
        author.name,
        author.email,
        format_timestamp(&author.timestamp)
    );

    // Committer
    let committer = commit.committer();
    println!(
        "Committer: {} <{}> ({})",
        committer.name,
        committer.email,
        format_timestamp(&committer.timestamp)
    );

    // Parents
    let root_commit_id = repo.store().root_commit_id().clone();
    for parent_id in commit.parent_ids() {
        if *parent_id == root_commit_id {
            continue;
        }
        let parent = repo.store().get_commit(parent_id)?;
        println!("Parent:    {}", common::format_commit_short(&parent));
    }

    // Children
    let children_ids = common::resolve_revset(
        workspace,
        repo,
        &format!("children({})", commit.id().hex()),
    )?;
    for child_id in &children_ids {
        if *child_id == root_commit_id {
            continue;
        }
        let child = repo.store().get_commit(child_id)?;
        println!("Child:     {}", common::format_commit_short(&child));
    }

    // Bookmarks
    let bookmark_str = format_bookmarks(commit, repo);
    if !bookmark_str.is_empty() {
        println!("Bookmarks: {bookmark_str}");
    }

    // Follows (nearest ancestor tag)
    let follows = find_nearest_tag(commit, repo, true)?;
    println!("Follows:   {}", follows.as_deref().unwrap_or(""));

    // Precedes (nearest descendant tag)
    let precedes = find_nearest_tag(commit, repo, false)?;
    println!("Precedes:  {}", precedes.as_deref().unwrap_or(""));

    Ok(())
}

fn find_nearest_tag(
    commit: &Commit,
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
    ancestor: bool,
) -> Result<Option<String>, Box<dyn std::error::Error>> {
    let commit_hex = commit.id().hex();

    // "follows": nearest ancestor tag = heads(tags() & ::commit)
    // "precedes": nearest descendant tag = roots(tags() & commit::)
    let revset_str = if ancestor {
        format!("heads(tags() & ::{})", commit_hex)
    } else {
        format!("roots(tags() & {}::)", commit_hex)
    };

    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
    if tag_ids.is_empty() {
        return Ok(None);
    }

    // Find the tag name for the first result
    let tag_id = &tag_ids[0];
    let view = repo.view();
    for (name, local_remote) in view.tags() {
        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
            return Ok(Some(name.as_str().to_string()));
        }
    }

    Ok(None)
}

fn format_bookmarks(commit: &Commit, repo: &Arc<ReadonlyRepo>) -> String {
    let view = repo.view();
    let mut names: Vec<String> = Vec::new();

    for (name, local_remote) in view.bookmarks() {
        // Local bookmark
        if local_remote
            .local_target
            .added_ids()
            .any(|id| id == commit.id())
        {
            names.push(name.as_str().to_string());
        }
        // Remote bookmarks
        for (remote_name, remote_ref) in &local_remote.remote_refs {
            if remote_ref.target.added_ids().any(|id| id == commit.id()) {
                names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
            }
        }
    }

    names.join(", ")
}

fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
    let millis = ts.timestamp.0;
