    for (name, local_remote) in view.bookmarks() {
        // Local bookmark
        if local_remote
            .local_target
            .added_ids()
            .any(|id| id == commit.id())
        {
            names.push(name.as_str().to_string());
        }
        // Remote bookmarks (skip "git" — internal colocated ref)
        for (remote_name, remote_ref) in &local_remote.remote_refs {
            if remote_name.as_str() == "git" {
