fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
    let millis = ts.timestamp.0;
    let secs = millis / 1000;
    let tz_minutes = ts.tz_offset;

    let dt = chrono::DateTime::from_timestamp(secs, 0)
        .unwrap_or_default()
        .with_timezone(
            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()),
        );

    dt.format("%Y-%m-%d %H:%M:%S").to_string()
}

fn print_description(commit: &Commit) {
    let desc = commit.description();
    // Skip the first line (title) — already shown on the Ids line
    let body: String = desc
        .lines()
        .skip(1)
        .skip_while(|l| l.is_empty()) // skip blank line between title and body
        .collect::<Vec<_>>()
        .join("\n");

    if body.is_empty() {
        println!("Description:");
    } else {
        println!("Description:");
        for line in body.lines() {
            println!("    {line}");
        }
    }
    println!();
}

