fn print_header(
    commit: &Commit,
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
) -> Result<(), Box<dyn std::error::Error>> {
    // Ids
    println!("Ids:       {}", common::format_commit_short(commit));

    // Author
    let author = commit.author();
    println!(
        "Author:    {} <{}> ({})",
        author.name,
        author.email,
        format_timestamp(&author.timestamp)
    );

    // Committer
    let committer = commit.committer();
    println!(
        "Committer: {} <{}> ({})",
        committer.name,
        committer.email,
        format_timestamp(&committer.timestamp)
    );

    // Parents
    let root_commit_id = repo.store().root_commit_id().clone();
    for parent_id in commit.parent_ids() {
        if *parent_id == root_commit_id {
            continue;
        }
        let parent = repo.store().get_commit(parent_id)?;
        println!("Parent:    {}", common::format_commit_short(&parent));
    }

    // Children
    let children_ids = common::resolve_revset(
        workspace,
        repo,
        &format!("children({})", commit.id().hex()),
