fn find_nearest_tag(
    commit: &Commit,
    workspace: &Workspace,
    repo: &Arc<ReadonlyRepo>,
    ancestor: bool,
) -> Result<Option<String>, Box<dyn std::error::Error>> {
    let commit_hex = commit.id().hex();

    // "follows": nearest ancestor tag = heads(tags() & ::commit)
    // "precedes": nearest descendant tag = roots(tags() & commit::)
    let revset_str = if ancestor {
        format!("heads(tags() & ::{})", commit_hex)
    } else {
        format!("roots(tags() & {}::)", commit_hex)
    };

