    #[arg(short = 'n', long = "files", default_value = "50")]
    pub files: String,

    /// Maximum number of commits to show
    #[arg(short, long)]
    pub limit: Option<usize>,

    /// Path to jj repo (default: current directory)
    #[arg(short = 'R', long, default_value = ".")]
    pub repo: PathBuf,
}

pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
    let file_limit = FileLimit::parse(&args.limit)?;

    let resolved = common::resolve_dot_args(
        args.pos_rev.as_deref(),
        args.pos_count,
        &args.revision,
        args.commit_limit,
        "@",
    );

